import os
import redis
from flask import Flask, request, jsonify
from dotenv import load_dotenv

load_dotenv()

app = Flask(__name__)

REDIS_HOST = os.getenv('REDIS_HOST')
REDIS_PORT = os.getenv('REDIS_PORT')
REDIS_PASSWORD = os.getenv('REDIS_PASSWORD')

redis_client = redis.StrictRedis(
    host=REDIS_HOST,
    port=REDIS_PORT,
    password=REDIS_PASSWORD,
    ssl=True,
    decode_responses=True
)

SESSION_TTL = 3600  # 1 hour
API_KEY_TTL = 86400  # 1 day

@app.route('/store_session', methods=['POST'])
def store_session():
    data = request.json
    session_id = data.get('session_id')
    session_token = data.get('session_token')
    if session_id and session_token:
        redis_client.setex(f'session:{session_id}', SESSION_TTL, session_token)
        return jsonify({'status': 'success'}), 200
    return jsonify({'status': 'error', 'message': 'Invalid data'}), 400

@app.route('/store_api_key', methods=['POST'])
def store_api_key():
    data = request.json
    user_id = data.get('user_id')
    api_key = data.get('api_key')
    if user_id and api_key:
        redis_client.setex(f'api_key:{user_id}', API_KEY_TTL, api_key)
        return jsonify({'status': 'success'}), 200
    return jsonify({'status': 'error', 'message': 'Invalid data'}), 400

@app.route('/get_session/<session_id>', methods=['GET'])
def get_session(session_id):
    session_token = redis_client.get(f'session:{session_id}')
    if session_token:
        return jsonify({'session_token': session_token}), 200
    return jsonify({'status': 'error', 'message': 'Session not found'}), 404

@app.route('/get_api_key/<user_id>', methods=['GET'])
def get_api_key(user_id):
    api_key = redis_client.get(f'api_key:{user_id}')
    if api_key:
        return jsonify({'api_key': api_key}), 200
    return jsonify({'status': 'error', 'message': 'API key not found'}), 404

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)